package main

import "fmt"

func targetSum(data []int) int {
    return countWays(data, 0, 0)
}

func countWays(data []int, index int, currentSum int) int {
    if index == len(data) {
        if currentSum == 0 {
            return 1
        }
        return 0
    }

    // Include the current number as positive
    positive := countWays(data, index+1, currentSum+data[index])
    // Include the current number as negative
    negative := countWays(data, index+1, currentSum-data[index])

    return positive + negative
}

func main() {
    data := []int{1, 1, 2, 3}
    fmt.Println(targetSum(data)) // Example usage
}

