class Solution {
    public int targetSum(int[] data) {
        int totalSum = 0;
        for (int num : data) {
            totalSum += num;
        }
        if (totalSum < 0 || (totalSum % 2 != 0)) {
            return 0;
        }
        int target = totalSum / 2;
        int n = data.length;
        int[] dp = new int[target + 1];
        dp[0] = 1;
        for (int num : data) {
            for (int j = target; j >= num; j--) {
                dp[j] += dp[j - num];
            }
        }
        return dp[target];
    }
}

